{"file_text": "@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings
@using sv_b4af5967487f4b3ebde86c22a3af8e58.Models

<div class="notifications-section">
    <h4>Notification Preferences</h4>

    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
                <div class="form-text">Receive notifications via email</div>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
                <div class="form-text">Receive push notifications in your browser</div>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                <div class="form-text">Receive a weekly summary email</div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title">Muted Channels</h6>
            <p class="text-muted small">Check a channel to mute notifications from it.</p>

            @foreach (var channel in AllChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="ch-@channel">
                        #@channel
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _saving;
    private string? _statusMessage;

    private static readonly string[] AllChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Preferences saved successfully!";
        }
        finally
        {
            _saving = false;
        }
    }
}
