@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings
@using sv_b4af5967487f4b3ebde86c22a3af8e58.Models

<div class="profile-section">
    <h4>Profile Settings</h4>

    @if (_statusMessage is not null)
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="avatar-area mb-4">
        <img src="@_displayName" alt="Avatar" class="avatar-placeholder" onerror="this.style.display='none'" style="display:none;" />
        <div class="avatar-preview">
            @if (!string.IsNullOrWhiteSpace(_avatarUrl))
            {
                <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
            }
            else
            {
                <div class="avatar-fallback">👤</div>
            }
        </div>
        <div class="avatar-url-display">
            <small class="text-muted">Avatar URL:</small>
            <code>@_avatarUrl</code>
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Display Name</label>
        <input type="text" class="form-control" @bind="_displayName" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Email</label>
        <input type="email" class="form-control" @bind="_email" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Bio</label>
        <textarea class="form-control" rows="4" @bind="_bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        _statusMessage = null;
    }
}

