arguments.file_text:
@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings

<div class="change-password-panel card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         @onclick="ToggleExpanded" role="button">
        <h6 class="mb-0">Change Password</h6>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (_statusMessage is not null)
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_statusMessage
                    <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePasswordAsync()
    {
        _statusMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _statusMessage = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _statusMessage = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch
        {
            _statusMessage = "Failed to update password.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

.change-password-panel .card-header {
    cursor: pointer;
    user-select: none;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings

<div class="modal-backdrop fade show"></div>
<div class="modal d-block fade show" tabindex="-1" role="dialog">
    <div class="modal-dialog modal-dialog-centered" role="document">
        <div class="modal-content">
            <div class="modal-header">
                <h5 class="modal-title">Revoke Session</h5>
                <button type="button" class="btn-close" @onclick="OnCancel"></button>
            </div>
            <div class="modal-body">
                <p>Are you sure you want to revoke the session on <strong>@Device</strong> from <strong>@Location</strong>?</p>
                <p class="text-muted small">This will log out the device immediately.</p>
            </div>
            <div class="modal-footer">
                <button type="button" class="btn btn-secondary" @onclick="OnCancel">Cancel</button>
                <button type="button" class="btn btn-danger" @onclick="OnConfirm">Revoke Session</button>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
}

@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings
@using sv_b4af5967487f4b3ebde86c22a3af8e58.Models

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title">Active Sessions</h6>

        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="text-muted">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => RequestRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
    </div>
</div>

@if (_sessionToRevoke is not null)
{
    <RevokeSessionDialog
        Device="@_sessionToRevoke.Device"
        Location="@_sessionToRevoke.Location"
        OnConfirm="ConfirmRevoke"
        OnCancel="CancelRevoke" />
}

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void RequestRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
