@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings

<div class="change-password-panel card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         @onclick="ToggleExpanded" role="button">
        <h6 class="mb-0">Change Password</h6>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (_statusMessage is not null)
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_statusMessage
                    <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePasswordAsync()
    {
        _statusMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _statusMessage = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _statusMessage = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch
        {
            _statusMessage = "Failed to update password.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

.change-password-panel .card-header {
    cursor: pointer;
    user-select: none;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

