        <div class="card-body">
            <h6 class="card-title">Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => ToggleTwoFactor((bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="twoFactor">
                        Enable Two-Factor Authentication
                    </label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>

            @if (Security?.LastPasswordChange is not null)
            {
                <div class="mt-3 text-muted small">
                    Last password change: @Security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </div>
            }
        </div>
    </div>

    <ActiveSessionsTable
        Sessions="Security?.Sessions?.ToList()"
        OnRevoke="HandleRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private bool _twoFactorEnabled;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            _twoFactorEnabled = Security.TwoFactorEnabled;
        }
    }

    private async Task HandleChangePassword((string Current, string New) passwords)
    {
        await OnChangePassword.InvokeAsync(passwords);
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private async Task ToggleTwoFactor(bool enabled)
    {
        _twoFactorEnabled = enabled;
        await OnToggleTwoFactor.InvokeAsync(enabled);
    }
}
