    <div class="card-body preview-body @ThemeClass @FontSizeClass @(CompactMode ? "compact" : "")">
        <h6>Preview</h6>
        <p class="preview-text">This is how your content will look with the selected settings.</p>
        <div class="preview-card">
            <strong>Sample Card</strong>
            <p class="mb-1">Here is some sample content in <em>@Language</em>.</p>
            <button class="btn btn-sm btn-primary">Sample Button</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public string Language { get; set; } = "English";
    [Parameter] public bool CompactMode { get; set; }

    private string ThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string FontSizeClass => FontSize switch
    {
        "Small" => "preview-font-sm",
        "Large" => "preview-font-lg",
        _ => "preview-font-md"
    };
}

.preview-area {
    border: 2px dashed #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

.preview-body {
    transition: all 0.3s ease;
    padding: 1.5rem;
}

.preview-card {
    background: rgba(0, 0, 0, 0.05);
    padding: 1rem;
    border-radius: 0.375rem;
    margin-top: 0.75rem;
}

/* Theme variants */
.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-dark {
    background-color: #1a1a2e;
    color: #e0e0e0;
}

.preview-dark .preview-card {
    background: rgba(255, 255, 255, 0.1);
}

.preview-system {
    background-color: #f0f0f0;
    color: #333;
}

/* Font size variants */
.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

/* Compact mode */
.compact {
    padding: 0.75rem !important;
    line-height: 1.3;
}

.compact .preview-card {
    padding: 0.5rem;
    margin-top: 0.5rem;
}

.compact p {
    margin-bottom: 0.25rem;
}

