arguments.file_text:
@page "/settings"
@namespace sv_b4af5967487f4b3ebde86c22a3af8e58.Components.Pages.Settings
@using sv_b4af5967487f4b3ebde86c22a3af8e58.Models
@using sv_b4af5967487f4b3ebde86c22a3af8e58.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionSelected="SwitchSection" />

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="_notificationPrefs" OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection
                        Security="_security"
                        OnChangePassword="ChangePasswordAsync"
                        OnRevokeSession="RevokeSessionAsync"
                        OnToggleTwoFactor="ToggleTwoFactorAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="_appearance" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionDataAsync(_activeSection);
    }

    private async Task SwitchSection(string section)
    {
        if (_activeSection == section) return;
        _activeSection = section;
        _loading = true;
        await LoadSectionDataAsync(section);
    }

    private async Task LoadSectionDataAsync(string section)
    {
        _loading = true;
        try
        {
            switch (section)
            {
                case "Profile":
                    _profile = await SettingsService.GetProfileAsync();
                    break;
                case "Notifications":
                    _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                    break;
                case "Security":
                    _security = await SettingsService.GetSecuritySettingsAsync();
                    break;
                case "Appearance":
                    _appearance = await SettingsService.GetAppearanceAsync();
                    break;
            }
        }
        finally
        {
            _loading = false;
        }
